sys_security_acl.script:
// Only club members with president or secretary role can create attendance records
// Must verify role in the membership table for the event's club
var eventGr = new GlideRecord('x_2097092_linq_event');
eventGr.get(current.getValue('event'));
var clubId = eventGr.getValue('club');

var gr = new GlideRecord('x_2097092_linq_club_membership');
gr.addQuery('member', gs.getUserID());
gr.addQuery('club', clubId);
gr.addQuery('status', 'active');
gr.addQuery('role', 'IN', 'president,secretary');
gr.query();
answer = gr.hasNext();
